Since `pthread_attr_setstackcommit()` is not a standard POSIX function, I'll provide a C++ example that demonstrates how to create a thread pool using `pthread` with standard attributes. This example will set the stack size to 4MB using `pthread_attr_setstacksize()`. If your platform supports `pthread_attr_setstackcommit()`, you would need to consult the specific documentation to see how to use it, as it is not part of the standard API.

Here's a basic example of creating a thread pool with a specified stack size:

```cpp
#include <iostream>
#include <pthread.h>
#include <vector>
#include <unistd.h> // For sleep function

// Function that each thread will execute
void* threadFunction(void* arg) {
    std::cout << "Thread " << pthread_self() << " is running.\n";
    sleep(1); // Simulate work
    return nullptr;
}

int main() {
    const int numThreads = 5;
    const size_t stackSize = 4 * 1024 * 1024; // 4MB

    pthread_attr_t attr;
    pthread_attr_init(&attr);

    // Set the stack size
    if (pthread_attr_setstacksize(&attr, stackSize) != 0) {
        std::cerr << "Failed to set stack size.\n";
        return 1;
    }

    // If your platform supports pthread_attr_setstackcommit(), you would set it here
    // Example (non-standard, hypothetical):
    // size_t stackCommit = 64 * 1024; // 64KB
    // pthread_attr_setstackcommit(&attr, stackCommit);

    std::vector<pthread_t> threads(numThreads);

    // Create threads
    for (int i = 0; i < numThreads; ++i) {
        if (pthread_create(&threads[i], &attr, threadFunction, nullptr) != 0) {
            std::cerr << "Failed to create thread " << i << ".\n";
            return 1;
        }
    }

    // Wait for threads to finish
    for (int i = 0; i < numThreads; ++i) {
        pthread_join(threads[i], nullptr);
    }

    pthread_attr_destroy(&attr);

    std::cout << "All threads have finished.\n";
    return 0;
}
```

This example initializes a thread attribute object, sets the stack size to 4MB, and creates a pool of threads using these attributes. Each thread runs a simple function that prints its ID and simulates some work with `sleep`.

If your platform supports `pthread_attr_setstackcommit()`, you would insert the call to set the stack commit size after setting the stack size, as shown in the commented-out section. However, since this function is not standard, you need to ensure your platform provides it and understand its usage from the platform-specific documentation.

`pthread_attr_setstackcommit()`은 표준 POSIX 스레드 라이브러리의 일부가 아니며, 특정 플랫폼에서만 제공되는 비표준 확장입니다. 따라서, 이 함수가 실제로 존재하고 사용할 수 있는지 여부는 사용하는 시스템에 따라 다릅니다. 일반적인 POSIX 시스템에서는 이 함수를 사용할 수 없습니다.

하지만, 스레드 풀을 생성하고 각 스레드의 스택 크기를 설정하는 방법을 보여주는 예제 코드를 작성할 수 있습니다. 이 예제에서는 `pthread_attr_setstacksize()`를 사용하여 스택 크기를 설정합니다. `pthread_attr_setstackcommit()`은 사용할 수 없으므로 포함하지 않습니다.

```cpp
#include <iostream>
#include <pthread.h>
#include <vector>

void* threadFunction(void* arg) {
    // 스레드가 수행할 작업을 여기에 작성합니다.
    std::cout << "Thread is running\n";
    return nullptr;
}

int main() {
    const int numThreads = 5;
    const size_t stackSize = 4 * 1024 * 1024; // 4MB

    std::vector<pthread_t> threads(numThreads);
    pthread_attr_t attr;

    // 스레드 속성 초기화
    if (pthread_attr_init(&attr) != 0) {
        std::cerr << "Failed to initialize thread attributes\n";
        return 1;
    }

    // 스택 크기 설정
    if (pthread_attr_setstacksize(&attr, stackSize) != 0) {
        std::cerr << "Failed to set stack size\n";
        pthread_attr_destroy(&attr);
        return 1;
    }

    // 스레드 생성
    for (int i = 0; i < numThreads; ++i) {
        if (pthread_create(&threads[i], &attr, threadFunction, nullptr) != 0) {
            std::cerr << "Failed to create thread\n";
            pthread_attr_destroy(&attr);
            return 1;
        }
    }

    // 스레드 속성 해제
    pthread_attr_destroy(&attr);

    // 스레드 종료 대기
    for (int i = 0; i < numThreads; ++i) {
        pthread_join(threads[i], nullptr);
    }

    return 0;
}
```

이 코드는 5개의 스레드를 생성하고 각 스레드에 대해 4MB의 스택을 설정합니다. `pthread_attr_setstackcommit()`을 사용할 수 있는 환경이라면, 해당 함수 호출을 추가하여 스택 커밋 크기를 설정할 수 있습니다. 하지만, 이 함수는 비표준적이므로 사용 가능한지 확인해야 합니다.

Certainly! Below is a concise C example demonstrating how to use `sendfile()` with a `chunk_size` of 1MB to transfer a large file over a TCP socket. The example includes basic error handling for partial sends.

```c
#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/sendfile.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>
#include <errno.h>

#define CHUNK_SIZE (1024 * 1024) // 1MB

int main(int argc, char *argv[]) {
    if (argc != 4) {
        fprintf(stderr, "Usage: %s <file> <ip> <port>\n", argv[0]);
        return EXIT_FAILURE;
    }

    const char *filename = argv[1];
    const char *ip = argv[2];
    int port = atoi(argv[3]);

    int file_fd = open(filename, O_RDONLY);
    if (file_fd < 0) {
        perror("open");
        return EXIT_FAILURE;
    }

    int sock_fd = socket(AF_INET, SOCK_STREAM, 0);
    if (sock_fd < 0) {
        perror("socket");
        close(file_fd);
        return EXIT_FAILURE;
    }

    struct sockaddr_in server_addr = {
        .sin_family = AF_INET,
        .sin_port = htons(port),
    };
    if (inet_pton(AF_INET, ip, &server_addr.sin_addr) <= 0) {
        perror("inet_pton");
        close(file_fd);
        close(sock_fd);
        return EXIT_FAILURE;
    }

    if (connect(sock_fd, (struct sockaddr *)&server_addr, sizeof(server_addr)) < 0) {
        perror("connect");
        close(file_fd);
        close(sock_fd);
        return EXIT_FAILURE;
    }

    off_t offset = 0;
    ssize_t bytes_sent;
    struct stat file_stat;
    if (fstat(file_fd, &file_stat) < 0) {
        perror("fstat");
        close(file_fd);
        close(sock_fd);
        return EXIT_FAILURE;
    }

    while (offset < file_stat.st_size) {
        size_t bytes_to_send = CHUNK_SIZE;
        if (offset + bytes_to_send > file_stat.st_size) {
            bytes_to_send = file_stat.st_size - offset;
        }

        bytes_sent = sendfile(sock_fd, file_fd, &offset, bytes_to_send);
        if (bytes_sent <= 0) {
            if (errno == EINTR || errno == EAGAIN) {
                continue; // Retry on interrupt or temporary unavailability
            }
            perror("sendfile");
            close(file_fd);
            close(sock_fd);
            return EXIT_FAILURE;
        }
    }

    printf("File transfer completed successfully.\n");

    close(file_fd);
    close(sock_fd);
    return EXIT_SUCCESS;
}
```

### Key Points:
- **Error Handling**: The code checks for errors at each step, including opening the file, creating the socket, connecting, and during the `sendfile()` call.
- **Partial Sends**: The loop continues until the entire file is sent, handling partial sends by adjusting the `offset` and `bytes_to_send`.
- **Chunk Size**: The `CHUNK_SIZE` is set to 1MB, and the code ensures that the last chunk does not exceed the file size.
- **Socket Connection**: The example assumes a TCP connection to a server specified by IP and port. Adjust the server-side to accept this connection for a complete test.

